(7, 'header_search_placeholder', 'ابحث عن المنتجات والعلامات التجارية...', 'text', 'header', 'نص placeholder لحقل البحث', '2025-11-04 15:36:58', '2025-11-04 15:36:58'),
(8, 'header_menu_items', '{\"main_pages\":[{\"title\":\"الرئيسية\",\"link\":\"\\/\"},{\"title\":\"المنتجات\",\"link\":\"\\/products\"},{\"title\":\"العروض\",\"link\":\"\\/offers\"}],\"customer_service\":[{\"title\":\"من نحن\",\"link\":\"\\/about\"},{\"title\":\"اتصل بنا\",\"link\":\"\\/contact\"},{\"title\":\"الشحن والتوصيل\",\"link\":\"\\/shipping\"},{\"title\":\"الإرجاع والاستبدال\",\"link\":\"\\/returns\"},{\"title\":\"الضمان\",\"link\":\"\\/warranty\"}],\"account\":[{\"title\":\"تسجيل الدخول\",\"link\":\"admin\\/login\"},{\"title\":\"إنشاء حساب\",\"link\":\"\\/register\"}]}', 'json', 'header', 'عناصر القائمة في Header', '2025-11-04 15:36:58', '2025-11-04 16:33:09'),
(9, 'about_hero_title', 'من نحن', 'text', 'about', 'عنوان قسم Hero في صفحة من نحن', '2025-11-04 16:06:44', '2025-11-04 16:06:44'),
(10, 'about_hero_description', 'نحن شركة رائدة في مجال ملابس الأطفال، نسعى لتقديم أفضل المنتجات والخدمات لعملائنا في فلسطين', 'text', 'about', 'وصف قسم Hero في صفحة من نحن', '2025-11-04 16:06:44', '2026-04-05 19:04:51'),
(11, 'about_story_title', 'قصتنا', 'text', 'about', 'عنوان قسم القصة', '2025-11-04 16:06:44', '2025-11-04 16:06:44'),
(12, 'about_story_content', 'نقدم ملابس أطفال مختارة بعناية مع اهتمام حقيقي بالجودة والراحة والتفاصيل.<div><br><div>&nbsp;نؤمن أن اختيار ملابس الأطفال لا يتعلق بالشكل فقط، بل بالراحة، الجودة، وسهولة الحركة. لذلك نعمل على تقديم خيارات مناسبة لكل يوم ولكل مناسبة.</div></div>', 'text', 'about', 'محتوى قسم القصة', '2026-04-05 19:12:36', '2026-04-05 19:35:11'),
(13, 'about_values', '[{\"title\":\"الجودة والتميز\",\"description\":\"نلتزم بتقديم أفضل المنتجات والخدمات لعملائنا الكرام\",\"icon\":\"target\"},{\"title\":\"رضا العملاء\",\"description\":\"رضاكم هو هدفنا الأول ونسعى دائماً لتجاوز توقعاتكم\",\"icon\":\"heart\"},{\"title\":\"الابتكار والتطوير\",\"description\":\"نواكب أحدث صيحات الموضة والملابس لتناسب اذواقكم\",\"icon\":\"zap\"},{\"title\":\"الثقة والأمان\",\"description\":\"نبني علاقات طويلة الأمد مع عملائنا على أساس الثقة\",\"icon\":\"shield\"}]', 'json', 'about', 'القيم والمبادئ', '2025-11-04 16:06:44', '2026-04-04 14:26:22'),
