(83, 'shipping_policies', '[{\"title\":\"ضمان الوصول الآمن\",\"description\":\"نضمن وصول منتجاتك بحالة ممتازة أو نستبدلها مجانا\"},{\"title\":\"التسليم في الوقت المحدد\",\"description\":\"نلتزم بمواعيد التسليم المحددة أو نقدم تعويضا\"},{\"title\":\"تغليف احترافي\",\"description\":\"نستخدم مواد تغليف عالية الجودة لحماية منتجاتك\"},{\"title\":\"تتبع مباشر\",\"description\":\"تابع شحنتك لحظة بلحظة عبر رقم التتبع\"}]', 'json', 'shipping', 'ضمانات وسياسات الشحن', '2026-04-24 11:04:34', '2026-04-24 11:04:34'),
