(85, 'shipping_notes', '[{\"title\":\"شروط الشحن المجاني\",\"description\":\"الشحن مجاني للطلبات التي تزيد قيمتها عن 500 شيكل داخل المدن الرئيسية في فلسطين.\",\"type\":\"info\"},{\"title\":\"الأجهزة الكبيرة\",\"description\":\"الأجهزة الكبيرة مثل الثلاجات والغسالات تحتاج موعد مسبق للتوصيل والتركيب.\",\"type\":\"warning\"},{\"title\":\"خدمة التركيب\",\"description\":\"نقدم خدمة التركيب المجاني للأجهزة الكبيرة مع ضمان على التركيب لمدة 6 أشهر.\",\"type\":\"success\"},{\"title\":\"المناطق النائية\",\"description\":\"قد تحتاج المناطق النائية وقتا إضافيا للتوصيل (5-7 أيام عمل) مع رسوم شحن إضافية.\",\"type\":\"danger\"}]', 'json', 'shipping', 'ملاحظات هامة في صفحة الشحن', '2026-04-24 11:04:34', '2026-04-24 11:04:34'),
(86, 'shipping_cta_title', 'هل لديك استفسار حول الشحن؟', 'text', 'shipping', 'عنوان دعوة التواصل في صفحة الشحن', '2026-04-24 11:04:34', '2026-04-24 11:04:34'),
